1	// A live cell's coordinates as [x, y]. The grid is unbounded;
2	// coordinates may be negative.
3	export type Cell = [number, number];
4	
5	const NEIGHBOR_OFFSETS: ReadonlyArray<readonly [number, number]> = [
6	  [-1, -1], [-1, 0], [-1, 1],
7	  [ 0, -1],          [ 0, 1],
8	  [ 1, -1], [ 1, 0], [ 1, 1],
9	];
10	
11	const cellKey = (x: number, y: number): string => `${x},${y}`;
12	
13	const countLiveNeighbors = (
14	  x: number,
15	  y: number,
16	  liveSet: ReadonlySet<string>,
17	): number =>
18	  NEIGHBOR_OFFSETS.filter(([dx, dy]) => liveSet.has(cellKey(x + dx, y + dy)))
19	    .length;
20	
21	const survivesToNextGeneration = (liveNeighborCount: number): boolean =>
22	  liveNeighborCount === 2 || liveNeighborCount === 3;
23	
24	export function nextGeneration(liveCells: Cell[]): Cell[] {
25	  const liveSet = new Set(liveCells.map(([x, y]) => cellKey(x, y)));
26	  const survivors = liveCells.filter(([x, y]) =>
27	    survivesToNextGeneration(countLiveNeighbors(x, y, liveSet)),
28	  );
29	  const candidateDeadCells = new Map<string, Cell>();
30	  for (const [x, y] of liveCells) {
31	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
32	      const nx = x + dx;
33	      const ny = y + dy;
34	      const key = cellKey(nx, ny);
35	      if (!liveSet.has(key)) candidateDeadCells.set(key, [nx, ny]);
36	    }
37	  }
38	  const births: Cell[] = [];
39	  for (const [x, y] of candidateDeadCells.values()) {
40	    if (countLiveNeighbors(x, y, liveSet) === 3) births.push([x, y]);
41	  }
42	  return [...survivors, ...births];
43	}
