const survivesToNextGeneration = (liveNeighborCount: number): boolean =>
  liveNeighborCount === 2 || liveNeighborCount === 3;

export function nextGeneration(liveCells: Cell[]): Cell[] {
  const liveSet = new Set(liveCells.map(([x, y]) => cellKey(x, y)));
  const survivors = liveCells.filter(([x, y]) =>
    survivesToNextGeneration(countLiveNeighbors(x, y, liveSet)),
  );
  const candidateDeadCells = new Map<string, Cell>();
  for (const [x, y] of liveCells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const nx = x + dx;
      const ny = y + dy;
      const key = cellKey(nx, ny);
      if (!liveSet.has(key)) candidateDeadCells.set(key, [nx, ny]);
    }
  }
  const births: Cell[] = [];
  for (const [x, y] of candidateDeadCells.values()) {
    if (countLiveNeighbors(x, y, liveSet) === 3) births.push([x, y]);
  }
  return [...survivors, ...births];
}

